import type { Metadata } from 'next'
import Image from 'next/image'
import Link from 'next/link'
import { notFound } from 'next/navigation'
import { ArrowLeft, Calendar, MapPin, ExternalLink } from 'lucide-react'
import { communityMembers } from '@/data/communityMembers'
import { cn } from '@/lib/utils'

export async function generateStaticParams() {
  return communityMembers.map((m) => ({ slug: m.slug }))
}

interface PageProps {
  params: Promise<{ slug: string }>
}

export async function generateMetadata({ params }: PageProps): Promise<Metadata> {
  const { slug } = await params
  const member = communityMembers.find((m) => m.slug === slug)
  if (!member) {
    return {
      title: 'Member Not Found | Dua Charitable Trust',
    }
  }
  return {
    title: `${member.name} — Community Member | Dua Charitable Trust`,
    description: member.contributionSummary,
  }
}

export default async function CommunityMemberProfilePage({ params }: PageProps) {
  const { slug } = await params
  const member = communityMembers.find((m) => m.slug === slug)

  if (!member) {
    notFound()
  }

  const displayRole = member.role.charAt(0).toUpperCase() + member.role.slice(1).toLowerCase()

  return (
    <main className="bg-[#FBF7F0] min-h-screen pt-24 sm:pt-28 md:pt-32 pb-16 md:pb-24 animate-[fadeIn_0.5s_ease-out]">
      <div className="max-w-5xl mx-auto px-4 lg:px-8 space-y-10">

        {/* Back Link */}
        <div className="flex items-center">
          <Link 
            href="/community" 
            className="inline-flex items-center gap-2 text-xs font-semibold uppercase tracking-widest text-brand-grey hover:text-brand-blue transition-colors duration-200"
          >
            <ArrowLeft size={14} /> Back to Community
          </Link>
        </div>

        {/* Hero Card */}
        <section 
          className="relative bg-white/90 backdrop-blur-md rounded-[32px] border border-brand-sand/30 shadow-card overflow-hidden"
          aria-label={`${member.name} profile card`}
        >
          {/* Top wide hero image / banner placeholder */}
          <div className="relative h-44 sm:h-56 md:h-72 w-full bg-brand-sand/20">
            {member.heroImageSrc ? (
              <Image 
                src={member.heroImageSrc} 
                alt="" 
                fill 
                className="object-cover" 
                priority 
                sizes="1024px" 
              />
            ) : (
              <div className="absolute inset-0 bg-gradient-to-tr from-brand-blue/25 via-brand-amber/10 to-brand-blue/10" />
            )}
            <div className="absolute inset-0 bg-gradient-to-t from-white/90 via-transparent to-transparent opacity-60" />
          </div>

          {/* Overlapping Avatar and Info Grid */}
          <div className="relative z-10 px-6 pb-8 md:px-10 md:pb-10 -mt-16 sm:-mt-20 md:-mt-24">
            <div className="flex flex-col md:flex-row md:items-center gap-6 md:gap-8 text-center md:text-left">
              {/* Profile Avatar */}
              <div className="w-28 h-28 sm:w-32 sm:h-32 md:w-36 md:h-36 min-w-28 min-h-28 sm:min-w-32 sm:min-h-32 md:min-w-36 md:min-h-36 rounded-full bg-gradient-to-tr from-brand-blue to-brand-amber p-[3px] flex-shrink-0 shadow-lg ring-8 ring-white relative mx-auto md:mx-0">
                <div className="w-full h-full rounded-full overflow-hidden bg-brand-cream relative">
                  <Image 
                    src={member.avatarSrc} 
                    alt={member.name} 
                    fill 
                    className="object-cover" 
                    priority 
                    sizes="(max-width: 768px) 112px, 144px" 
                  />
                </div>
              </div>

              {/* Main Info */}
              <div className="flex-1 space-y-3">
                <div className="flex flex-wrap items-center justify-center md:justify-start gap-2">
                  <span className={cn(
                    'text-[10px] font-bold uppercase tracking-wider px-3 py-1 rounded-full border shadow-sm', 
                    member.role === 'DONOR' 
                      ? 'bg-brand-amber/10 text-brand-amber-dark border-brand-amber/25' 
                      : 'bg-brand-blue/10 text-brand-blue border-brand-blue/25'
                  )}>
                    {displayRole}
                  </span>
                  {member.focusTags.map((tag) => (
                    <span 
                      key={tag} 
                      className="bg-brand-sand/40 text-brand-charcoal/70 text-[10px] font-semibold px-3 py-1 rounded-full border border-brand-sand/60"
                    >
                      {tag}
                    </span>
                  ))}
                </div>
                <h1 className="font-heading font-bold text-brand-charcoal text-3xl sm:text-4xl md:text-5xl leading-tight">
                  {member.name}
                </h1>
                <p className="text-sm md:text-base font-body font-bold text-brand-blue">
                  {member.contributionTitle}
                </p>
              </div>
            </div>
          </div>
        </section>

        {/* Details Grid */}
        <div className="grid gap-8 md:grid-cols-[2fr,1.3fr]">

          {/* Left Column: About & Story */}
          <section className="space-y-6" aria-label="About and Bio">
            <div className="bg-white rounded-[32px] p-6 sm:p-8 md:p-10 border border-brand-sand/30 shadow-card space-y-6">
              <h2 className="font-heading font-bold text-brand-charcoal text-2xl md:text-3xl">
                About {member.name}
              </h2>
              <div className="prose prose-lg max-w-none font-body text-brand-grey leading-relaxed space-y-5">
                {member.longBio.trim().split('\n\n').map((para, i) => (
                  <p key={i} className="text-sm sm:text-base">{para.trim()}</p>
                ))}
              </div>

              <div className="pt-6 border-t border-brand-sand/30 flex flex-wrap gap-4 text-xs font-body text-brand-grey/80">
                <span className="flex items-center gap-1.5 bg-[#FBF7F0] px-3.5 py-2 rounded-full border border-brand-sand/40">
                  <Calendar size={14} className="text-brand-blue" />
                  Joined {member.joinedYear}
                </span>
                <span className="flex items-center gap-1.5 bg-[#FBF7F0] px-3.5 py-2 rounded-full border border-brand-sand/40">
                  <MapPin size={14} className="text-brand-amber-dark" />
                  {member.location || 'Location not specified'}
                </span>
              </div>
            </div>
          </section>

          {/* Right Column: Impact & Highlights */}
          <section className="space-y-6" aria-label="Highlights and Stats">
            {/* Card 1: Key Contribution */}
            <div className="bg-white rounded-[32px] p-6 border border-brand-sand/30 shadow-card space-y-4">
              <h3 className="font-heading font-bold text-brand-charcoal text-base">Key Contribution</h3>
              <div className="bg-[#FBF7F0]/60 rounded-2xl p-4 border border-brand-sand/20 space-y-1">
                <p className="text-[10px] font-body font-bold text-brand-grey uppercase tracking-wider">Contribution</p>
                <p className="text-xs sm:text-sm font-body font-bold text-brand-blue">{member.contributionTitle}</p>
              </div>
              <p className="text-xs font-body text-brand-grey/90 leading-relaxed">
                {member.contributionSummary}
              </p>
            </div>

            {/* Card 2: Impact Snapshot */}
            {member.impactStats && member.impactStats.length > 0 && (
              <div className="bg-white rounded-[32px] p-6 border border-brand-sand/30 shadow-card space-y-4">
                <h3 className="font-heading font-bold text-brand-charcoal text-base">Impact Snapshot</h3>
                <div className="grid gap-3">
                  {member.impactStats.map((stat, idx) => (
                    <div 
                      key={idx} 
                      className="bg-[#FBF7F0]/40 rounded-xl p-4 border border-brand-sand/20 flex flex-col justify-center gap-1 hover:border-brand-amber/30 transition-all duration-300"
                    >
                      <p className="font-heading font-bold text-brand-blue text-lg leading-none">{stat.value}</p>
                      <p className="font-body text-[9px] uppercase tracking-wider font-bold text-brand-grey/70">{stat.label}</p>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Card 3: Connect CTA */}
            <div className="bg-gradient-to-br from-[#1A3A5C] via-[#11243B] to-[#1C1C1E] border border-white/10 rounded-[32px] p-6 text-white shadow-card-hover relative overflow-hidden group">
              {/* Ambient Glow */}
              <div className="absolute -top-20 -right-20 w-32 h-32 bg-brand-amber/15 rounded-full blur-2xl pointer-events-none group-hover:scale-110 transition-transform duration-500" />

              <div className="relative z-10 space-y-4">
                <h3 className="font-heading font-bold text-base text-white">Connect</h3>
                <p className="font-body text-white/80 text-xs leading-relaxed">
                  Interested in collaborating with {member.name} or supporting their initiatives? Reach out via Dua Charitable Trust.
                </p>
                <Link 
                  href="/contact" 
                  className="inline-flex items-center gap-1.5 text-xs font-semibold text-brand-amber hover:text-white transition-colors duration-200"
                >
                  Contact Us <ExternalLink size={12} />
                </Link>
              </div>
            </div>
          </section>

        </div>
      </div>
    </main>
  )
}


@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,500;0,600;0,700;1,400;1,600&family=Inter:wght@300;400;500;600;700&display=swap');

@import "tailwindcss";

/* ─── Keyframes (must be outside @theme) ────────────────── */
@keyframes fadeUp {
  from {
    opacity: 0;
    transform: translateY(24px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes fadeInUp {
  0% {
    opacity: 0;
    transform: translateY(32px) scale(0.98);
  }
  100% {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

@keyframes shimmer {
  0% { background-position: -200% center; }
  100% { background-position: 200% center; }
}

@keyframes pulseSoft {
  0%, 100% { opacity: 0.6; }
  50% { opacity: 1; }
}

@keyframes pulseDot {

  0%,
  100% {
    transform: scale(1);
    opacity: 1;
  }

  50% {
    transform: scale(1.4);
    opacity: 0.6;
  }
}

/* ─── Tailwind v4 Theme ──────────────────────────────────── */
@theme {
  /* Brand Colors */
  --color-brand-blue: #1A3A5C;
  --color-brand-blue-light: #4A7FA5;
  --color-brand-amber: #F0A92A;
  --color-brand-amber-dark: #D48B0E;
  --color-brand-cream: #FBF7F0;
  --color-brand-sand: #F0EAD8;
  --color-brand-charcoal: #1C1C1E;
  --color-brand-grey: #6E6A66;
  --color-brand-white: #FFFFFF;

  /* Font Families */
  --font-family-heading: 'Playfair Display', Georgia, serif;
  --font-family-body: 'Inter', system-ui, sans-serif;

  /* Border Radius */
  --radius-pill: 999px;

  /* Shadows */
  --shadow-card: 0 2px 16px 0 rgba(26, 58, 92, 0.08);
  --shadow-card-hover: 0 8px 32px 0 rgba(26, 58, 92, 0.16);
  --shadow-nav: 0 4px 24px 0 rgba(26, 58, 92, 0.10);

  /* Animations */
  --animate-fade-up: fadeUp 0.6s ease-out both;
  --animate-fade-in-up: fadeInUp 0.6s cubic-bezier(0.23, 1, 0.32, 1) both;
  --animate-shimmer: shimmer 2.5s infinite;
  --animate-pulse-soft: pulseSoft 3s ease-in-out infinite;
  --animate-pulse-dot: pulseDot 2s ease-in-out infinite;
}

/* ─── Root Variables ─────────────────────────────────────── */
:root {
  --section-y: clamp(60px, 8vw, 100px);
}

/* ─── Base Resets ────────────────────────────────────────── */
*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  background-color: #FBF7F0;
  color: #1C1C1E;
  font-family: 'Inter', system-ui, sans-serif;
  line-height: 1.65;
  font-size: 16px;
}

@media (min-width: 1024px) {
  body {
    font-size: 18px;
  }
}

h1,
h2,
h3,
h4,
h5,
h6 {
  font-family: 'Playfair Display', Georgia, serif;
  line-height: 1.2;
  color: #1C1C1E;
}

::selection {
  background-color: #F0A92A;
  color: #1C1C1E;
}

*:focus-visible {
  outline: 2px solid #F0A92A;
  outline-offset: 2px;
}

input:focus-visible,
select:focus-visible,
textarea:focus-visible,
.rounded-full:focus-visible {
  outline: none;
}

/* ─── Layout Utilities ───────────────────────────────────── */
.section-padding {
  padding-top: var(--section-y);
  padding-bottom: var(--section-y);
}

.container-wide {
  max-width: 80rem;
  margin-left: auto;
  margin-right: auto;
  padding-left: 1rem;
  padding-right: 1rem;
}

@media (min-width: 640px) {
  .container-wide {
    padding-left: 1.5rem;
    padding-right: 1.5rem;
  }
}

@media (min-width: 1024px) {
  .container-wide {
    padding-left: 2rem;
    padding-right: 2rem;
  }
}

/* ─── Buttons ────────────────────────────────────────────── */
.btn-primary,
.btn-amber,
.btn-ghost,
.btn-ghost-white {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  padding: 0.75rem 1.5rem;
  border-radius: 999px;
  font-family: 'Inter', system-ui, sans-serif;
  font-weight: 500;
  font-size: 0.875rem;
  min-height: 44px;
  transition: all 0.2s ease;
  border: none;
  cursor: pointer;
  text-decoration: none;
  line-height: 1;
}

.btn-primary {
  background-color: #1A3A5C;
  color: white;
}

.btn-primary:hover {
  background-color: #243f68;
  box-shadow: 0 8px 32px 0 rgba(26, 58, 92, 0.16);
  transform: translateY(-2px);
}

.btn-primary:active {
  transform: translateY(0);
}

.btn-amber {
  background-color: #F0A92A;
  color: #1C1C1E;
}

.btn-amber:hover {
  background-color: #D48B0E;
  box-shadow: 0 8px 32px 0 rgba(26, 58, 92, 0.16);
  transform: translateY(-2px);
}

.btn-amber:active {
  transform: translateY(0);
}

.btn-ghost {
  border: 1px solid #1A3A5C;
  color: #1A3A5C;
  background: transparent;
}

.btn-ghost:hover {
  background-color: #1A3A5C;
  color: white;
  transform: translateY(-2px);
}

.btn-ghost-white {
  border: 1px solid white;
  color: white;
  background: transparent;
}

.btn-ghost-white:hover {
  background-color: white;
  color: #1A3A5C;
  transform: translateY(-2px);
}

/* ─── Card ───────────────────────────────────────────────── */
.card {
  background: white;
  border-radius: 32px;
  box-shadow: 0 2px 16px 0 rgba(26, 58, 92, 0.08);
  transition: all 0.3s ease;
}

.card:hover {
  box-shadow: 0 8px 32px 0 rgba(26, 58, 92, 0.16);
  transform: translateY(-4px);
}

/* ─── Badges ─────────────────────────────────────────────── */
.badge {
  display: inline-block;
  padding: 0.25rem 0.75rem;
  border-radius: 999px;
  font-size: 0.75rem;
  font-weight: 500;
  font-family: 'Inter', system-ui, sans-serif;
}

.badge-blue {
  background: #EFF6FF;
  color: #1A3A5C;
}

.badge-amber {
  background: #FFFBEB;
  color: #D48B0E;
}

.badge-sand {
  background: #F0EAD8;
  color: #6E6A66;
}

/* ─── Typography Helpers ─────────────────────────────────── */
.section-label {
  font-size: 0.75rem;
  font-family: 'Inter', system-ui, sans-serif;
  font-weight: 600;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: #4A7FA5;
}

.section-title {
  font-family: 'Playfair Display', Georgia, serif;
  font-size: clamp(1.75rem, 3vw, 3rem);
  color: #1C1C1E;
  line-height: 1.2;
}

.section-subtitle {
  font-family: 'Inter', system-ui, sans-serif;
  font-size: clamp(1rem, 1.5vw, 1.125rem);
  color: #6E6A66;
  line-height: 1.65;
  max-width: 42rem;
}

/* ─── Navbar Pill ────────────────────────────────────────── */
.nav-pill {
  position: fixed;
  top: 1rem;
  left: 50%;
  transform: translateX(-50%);
  z-index: 50;
  width: calc(100% - 2rem);
  max-width: 72rem;
  background-color: rgba(255, 255, 255, 0.85);
  backdrop-filter: blur(12px);
  border-radius: 999px;
  box-shadow: 0 4px 24px 0 rgba(26, 58, 92, 0.10);
  border: 1px solid rgba(255, 255, 255, 0.6);
  transition: all 0.3s ease;
}

/* ─── Hero Overlay ───────────────────────────────────────── */
.hero-overlay {
  background: linear-gradient(to bottom,
      rgba(26, 58, 92, 0.60) 0%,
      rgba(26, 58, 92, 0.30) 50%,
      rgba(0, 0, 0, 0.15) 100%);
  position: absolute;
  inset: 0;
}

/* ─── Scroll Reveal ──────────────────────────────────────── */
.reveal {
  opacity: 0;
  transform: translateY(1.5rem);
  transition: all 0.7s ease-out;
}

.reveal.visible {
  opacity: 1;
  transform: translateY(0);
}

/* ─── Scrollbar ──────────────────────────────────────────── */
::-webkit-scrollbar {
  width: 6px;
}

::-webkit-scrollbar-track {
  background: #FBF7F0;
}

::-webkit-scrollbar-thumb {
  background: #4A7FA5;
  border-radius: 999px;
}

::-webkit-scrollbar-thumb:hover {
  background: #1A3A5C;
}


import Link from 'next/link'
import Image from 'next/image'
import { Calendar, User, ArrowRight, Tag } from 'lucide-react'
import { formatDate } from '@/lib/utils'

export interface BlogCardProps {
  slug: string
  title: string
  excerpt: string
  coverImage: string
  author?: string
  publishDate: string
  category: string
  featured?: boolean
}

export default function BlogCard({
  slug,
  title,
  excerpt,
  coverImage,
  author,
  publishDate,
  category,
  featured = false,
}: BlogCardProps) {
  return (
    <article
      className={`card overflow-hidden flex flex-col group border border-brand-sand/35 hover:border-brand-amber/30 transition-all duration-300 ${featured ? 'md:flex-row' : ''}`}
      aria-label={`Blog post: ${title}`}
    >
      {/* Image */}
      <div className={`relative overflow-hidden flex-shrink-0 ${featured ? 'md:w-2/5' : ''}`}>
        <div className={`relative ${featured ? 'h-56 md:h-full' : 'h-48'}`}>
          <Image
            src={coverImage}
            alt={title}
            fill
            className="object-cover transition-transform duration-700 group-hover:scale-105"
            sizes={featured ? '(max-width:768px) 100vw, 40vw' : '(max-width:768px) 100vw, 33vw'}
          />
        </div>
        {/* Category badge over image - premium top-right position */}
        <span className="absolute top-4 right-4 z-20 bg-gradient-to-r from-brand-amber to-amber-300 text-brand-charcoal text-[9px] font-bold tracking-widest uppercase px-3 py-1.5 rounded-full shadow-lg border border-brand-amber/20 transition-transform group-hover:scale-105 duration-300">
          {category}
        </span>
      </div>

      {/* Content */}
      <div className="flex flex-col flex-1 p-5">
        {/* Meta */}
        <div className="flex items-center gap-3 mb-3">
          <span className="flex items-center gap-1 text-xs text-brand-grey font-body">
            <Calendar size={12} />
            {formatDate(publishDate)}
          </span>
          {author && (
            <span className="flex items-center gap-1 text-xs text-brand-grey font-body">
              <User size={12} />
              {author}
            </span>
          )}
        </div>

        {/* Title */}
        <h3 className={`font-heading font-semibold text-brand-charcoal mb-2 leading-snug
                        group-hover:text-brand-blue transition-colors duration-200
                        ${featured ? 'text-xl sm:text-2xl' : 'text-lg'}`}>
          {title}
        </h3>

        {/* Excerpt */}
        <p className="font-body text-sm text-brand-grey leading-relaxed line-clamp-3 flex-1 mb-4">
          {excerpt}
        </p>

        {/* Read More */}
        <Link
          href={`/blog/${slug}`}
          className="inline-flex items-center gap-1.5 text-sm font-medium font-body text-brand-blue
                     hover:text-brand-amber-dark hover:gap-2.5
                     transition-all duration-200 mt-auto"
          aria-label={`Read more about ${title}`}
        >
          Read More
          <ArrowRight size={14} />
        </Link>
      </div>
    </article>
  )
}


import Image from 'next/image'
import Link from 'next/link'
import { cn } from '@/lib/utils'

interface CommunityCardProps {
  id: string
  name: string
  avatarSrc: string
  role: 'DONOR' | 'VOLUNTEER' | 'STAFF' | 'PARTNER'
  focusTags: string[]
  joinedYear: string
  contributionTitle: string
  contributionSummary: string
  slug: string
  className?: string
}

export default function CommunityCard({
  id,
  name,
  avatarSrc,
  role,
  focusTags,
  joinedYear,
  contributionTitle,
  contributionSummary,
  slug,
  className,
}: CommunityCardProps) {
  const category = focusTags[0] || 'Community'

  return (
    <div
      className={cn(
        "group relative overflow-hidden cursor-pointer rounded-[20px] p-5 border border-[#E8A53D]/15 transition-all duration-[450ms] ease-[cubic-bezier(0.23,1,0.32,1)] hover:-translate-y-2 hover:scale-[1.01] hover:border-[#E8A53D]/35 hover:shadow-[0_24px_48px_rgba(10,26,58,0.12),0_8px_20px_rgba(10,26,58,0.08),0_0_0_1px_rgba(232,165,61,0.2)] flex flex-col justify-between h-full",
        className
      )}
      style={{
        background: 'radial-gradient(ellipse at center, rgba(232,165,61,0.05), transparent 70%), linear-gradient(160deg, #FFFFFF 0%, #FDFAF4 50%, #FAF6ED 100%)',
        boxShadow: '0 1px 2px rgba(10,26,58,0.04), 0 4px 16px rgba(10,26,58,0.06), 0 12px 32px rgba(10,26,58,0.05)'
      }}
    >
      {/* ── SHIMMER TOP LINE ── */}
      <div
        className="absolute top-0 left-1/2 -translate-x-1/2 w-2/3 h-[1.5px] pointer-events-none"
        style={{
          background: 'linear-gradient(90deg, transparent, rgba(232,165,61,0.7), transparent)'
        }}
      />

      {/* ── HOVER ANIMATED GOLD LINE BOTTOM ── */}
      <div
        className="absolute bottom-0 left-0 right-0 h-[2px] bg-[#E8A53D] origin-left scale-x-0 group-hover:scale-x-100 transition-transform duration-500 ease-[cubic-bezier(0.23,1,0.32,1)] pointer-events-none"
      />

      {/* ── THIN ARC LINE DECORATION TOP LEFT ── */}
      <svg
        className="absolute top-0 left-0 w-16 h-16 pointer-events-none"
        viewBox="0 0 100 100"
        fill="none"
        xmlns="http://www.w3.org/2000/svg"
        aria-hidden="true"
      >
        <path
          d="M 0 60 A 60 60 0 0 0 60 0"
          stroke="rgba(232, 165, 61, 0.12)"
          strokeWidth="1"
          fill="none"
        />
      </svg>

      {/* ── SMALL BLOB TOP RIGHT ── */}
      <div
        className="absolute -top-5 -right-5 w-28 h-28 rounded-full pointer-events-none"
        style={{
          background: 'radial-gradient(circle, rgba(232,165,61,0.05) 0%, transparent 70%)'
        }}
      />

      {/* ── TINY DOT GRID BOTTOM LEFT ── */}
      <div className="absolute bottom-4 left-4 grid grid-cols-3 gap-1 pointer-events-none opacity-30">
        {[...Array(9)].map((_, i) => (
          <div
            key={i}
            className="w-0.5 h-0.5 rounded-full"
            style={{ background: 'rgba(232,165,61,0.5)' }}
          />
        ))}
      </div>

      <div>
        {/* ════════ PROFILE HEADER ════════ */}
        <div className="relative flex items-center gap-3 mb-4">
          {/* AVATAR */}
          <div className="relative flex-shrink-0">
            <div
              className="w-[50px] h-[50px] rounded-full p-[2px] group-hover:scale-105 transition-transform duration-300"
              style={{
                background: 'linear-gradient(135deg, #E8A53D, #F4C06A, #E8A53D)',
              }}
            >
              <div className="w-full h-full rounded-full p-[1.5px] bg-white relative overflow-hidden">
                <Image
                  src={avatarSrc}
                  alt={name}
                  fill
                  className="rounded-full object-cover"
                  sizes="50px"
                />
              </div>
            </div>

            {/* ROLE DOT */}
            <div
              className={`absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full ring-2 ring-white ${
                role === 'DONOR'
                  ? 'bg-gradient-to-br from-[#E8A53D] to-[#F4C06A]'
                  : 'bg-gradient-to-br from-[#0A1A3A] to-[#1E3A6E]'
              }`}
            />
          </div>

          {/* NAME + BADGES */}
          <div className="flex-1 min-w-0 font-body">
            {/* NAME */}
            <h3
              className="text-[#0A1A3A] font-bold leading-tight mb-1.5 truncate tracking-[-0.3px] group-hover:text-brand-blue transition-colors duration-300"
              style={{ fontSize: '15px' }}
            >
              {name}
            </h3>

            {/* BADGES */}
            <div className="flex items-center gap-1.5 flex-wrap">
              {role === 'DONOR' && (
                <span
                  className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[9px] font-bold uppercase tracking-[1.2px] text-white"
                  style={{
                    background: 'linear-gradient(135deg, #C8860D, #E8A53D, #F4C06A)',
                    boxShadow: '0 2px 8px rgba(232,165,61,0.40)'
                  }}
                >
                  ♦ Donor
                </span>
              )}

              {role === 'VOLUNTEER' && (
                <span
                  className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[9px] font-bold uppercase tracking-[1.2px] text-white"
                  style={{
